window.addEventListener("DOMContentLoaded",(function(){scrollPage(),bg()}));const bg=()=>{document.querySelectorAll(".ibg").forEach(e=>{e.querySelector("img")&&(e.style.backgroundImage="url("+e.querySelector("img").getAttribute("src")+")",e.querySelector("img").style.display="none")})},scrollPage=()=>{let e;const t=document.querySelector(".header");window.addEventListener("scroll",(function(){e=window.scrollY,e>=1?t.classList.add("hide"):t.classList.remove("hide")}))};